import { useState, useMemo, useEffect } from 'react'
import { useNavigate, Link } from 'react-router-dom'
import {
  CreditCard,
  Lock,
  CheckCircle2,
  ChevronRight,
  ShoppingBag,
  Copy,
  ShieldCheck,
  Zap,
  QrCode,
  Tag,
  AlertCircle,
} from 'lucide-react'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Separator } from '@/components/ui/separator'
import { RadioGroup, RadioGroupItem } from '@/components/ui/radio-group'
import { Badge } from '@/components/ui/badge'
import { useToast } from '@/hooks/use-toast'
import useCartStore from '@/stores/useCartStore'
import useUserStore from '@/stores/useUserStore'
import useOrderStore from '@/stores/useOrderStore'
import useCouponStore from '@/stores/useCouponStore'
import useAdminUserStore from '@/stores/useAdminUserStore'

export default function Checkout() {
  const navigate = useNavigate()
  const { toast } = useToast()
  const { items: cartItems, clearCart } = useCartStore()
  const { addOrder, addPurchasedItems } = useUserStore()
  const { addOrder: addGlobalOrder, orders: globalOrders } = useOrderStore()
  const { coupons, updateCoupon } = useCouponStore()
  const { markUserAsRecurring } = useAdminUserStore()

  const [isSuccess, setIsSuccess] = useState(false)
  const [isLoading, setIsLoading] = useState(false)
  const [paymentMethod, setPaymentMethod] = useState<'credit_card' | 'pix'>('credit_card')
  const [pixKey, setPixKey] = useState('')
  const [name, setName] = useState('')
  const [email, setEmail] = useState('')
  const [couponCode, setCouponCode] = useState('')
  const [autoAppliedEmail, setAutoAppliedEmail] = useState('')
  const [appliedDiscount, setAppliedDiscount] = useState<{
    id: string
    code: string
    type: 'percentage' | 'fixed'
    value: number
  } | null>(null)

  useEffect(() => {
    let key = '00020126360014BR.GOV.BCB.PIX0114'
    const chars = 'abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789'
    for (let i = 0; i < 35; i++) key += chars.charAt(Math.floor(Math.random() * chars.length))
    setPixKey(key)
  }, [])

  useEffect(() => {
    if (email && email.includes('@') && email !== autoAppliedEmail) {
      const hasPreviousOrders = globalOrders.some(
        (o) => o.customerEmail.toLowerCase() === email.toLowerCase(),
      )

      if (!hasPreviousOrders && !appliedDiscount) {
        const welcomeCoupon = coupons.find((c) => c.isWelcomeCoupon && c.isActive)

        if (welcomeCoupon) {
          const isExpired =
            welcomeCoupon.expirationDate &&
            new Date(welcomeCoupon.expirationDate) < new Date(new Date().setHours(0, 0, 0, 0))

          if (!isExpired) {
            setAppliedDiscount({
              id: welcomeCoupon.id,
              code: welcomeCoupon.code,
              type: welcomeCoupon.type,
              value: welcomeCoupon.value,
            })
            setCouponCode(welcomeCoupon.code)
            toast({
              title: 'Desconto de Boas-Vindas!',
              description:
                'Como esta é sua primeira compra, aplicamos um desconto automaticamente.',
            })
          }
        }
      } else if (hasPreviousOrders && appliedDiscount) {
        const currentCoupon = coupons.find((c) => c.id === appliedDiscount.id)
        if (currentCoupon?.isWelcomeCoupon) {
          setAppliedDiscount(null)
          setCouponCode('')
          toast({
            title: 'Cupom removido',
            description: 'O cupom de boas-vindas é válido apenas para a primeira compra.',
            variant: 'destructive',
          })
        }
      }

      setAutoAppliedEmail(email)
    }
  }, [email, globalOrders, coupons, appliedDiscount, toast, autoAppliedEmail])

  const checkoutItems = cartItems

  const subtotal = checkoutItems.reduce((acc, item) => acc + item.price * item.quantity, 0)

  const discountAmount = useMemo(() => {
    if (!appliedDiscount) return 0
    if (appliedDiscount.type === 'percentage') return subtotal * (appliedDiscount.value / 100)
    return appliedDiscount.value
  }, [appliedDiscount, subtotal])

  const total = Math.max(0, subtotal - discountAmount)

  if (checkoutItems.length === 0 && !isSuccess) {
    return (
      <div className="container mx-auto px-4 py-20 text-center max-w-lg">
        <ShoppingBag className="w-16 h-16 text-muted-foreground mx-auto mb-6 opacity-30" />
        <h2 className="text-2xl font-bold mb-4">Nenhum produto selecionado</h2>
        <Button size="lg" onClick={() => navigate('/')}>
          Voltar para a Loja
        </Button>
      </div>
    )
  }

  const handleApplyCoupon = () => {
    if (appliedDiscount) {
      setAppliedDiscount(null)
      setCouponCode('')
      toast({ title: 'Cupom removido', description: 'O desconto foi retirado do seu pedido.' })
      return
    }

    const code = couponCode.trim().toUpperCase()
    if (!code) return

    const coupon = coupons.find((c) => c.code === code)
    if (coupon) {
      if (!coupon.isActive) {
        toast({
          title: 'Cupom inativo',
          description: 'Este cupom não está mais ativo.',
          variant: 'destructive',
        })
        return
      }
      if (
        coupon.expirationDate &&
        new Date(coupon.expirationDate) < new Date(new Date().setHours(0, 0, 0, 0))
      ) {
        toast({
          title: 'Cupom expirado',
          description: 'A data de validade deste cupom já passou.',
          variant: 'destructive',
        })
        return
      }

      if (coupon.isWelcomeCoupon) {
        if (!email) {
          toast({
            title: 'E-mail necessário',
            description: 'Preencha seu e-mail antes de aplicar um cupom de boas-vindas.',
            variant: 'destructive',
          })
          return
        }
        const hasPreviousOrders = globalOrders.some(
          (o) => o.customerEmail.toLowerCase() === email.toLowerCase(),
        )
        if (hasPreviousOrders) {
          toast({
            title: 'Cupom inválido',
            description: 'O cupom de boas-vindas é exclusivo para a primeira compra.',
            variant: 'destructive',
          })
          return
        }
      }

      setAppliedDiscount({
        id: coupon.id,
        code: coupon.code,
        type: coupon.type,
        value: coupon.value,
      })
      toast({ title: 'Cupom aplicado!', description: 'Desconto adicionado ao seu pedido.' })
    } else {
      toast({
        title: 'Cupom inválido',
        description: 'Verifique o código e tente novamente.',
        variant: 'destructive',
      })
    }
  }

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault()

    if (appliedDiscount) {
      const coupon = coupons.find((c) => c.id === appliedDiscount.id)
      if (coupon?.isWelcomeCoupon) {
        const hasPreviousOrders = globalOrders.some(
          (o) => o.customerEmail.toLowerCase() === email.toLowerCase(),
        )
        if (hasPreviousOrders) {
          toast({
            title: 'Cupom inválido',
            description: 'O cupom de boas-vindas é exclusivo para a primeira compra.',
            variant: 'destructive',
          })
          return
        }
      }
    }

    setIsLoading(true)
    setTimeout(() => {
      setIsLoading(false)
      setIsSuccess(true)
      const orderId = `ORD-${Math.floor(1000 + Math.random() * 9000)}`
      const orderDate = new Date().toISOString()
      const mappedItems = checkoutItems.map((i) => ({
        productId: i.id,
        title: i.title,
        quantity: i.quantity,
        price: i.price,
      }))

      if (appliedDiscount && appliedDiscount.id) {
        const coupon = coupons.find((c) => c.id === appliedDiscount.id)
        if (coupon) {
          updateCoupon(coupon.id, { usageCount: coupon.usageCount + 1 })
        }
      }

      const newOrder = {
        id: orderId,
        date: orderDate,
        total,
        status: 'Concluído',
        items: mappedItems,
      }
      addOrder(newOrder)
      addPurchasedItems(checkoutItems.map((i) => i.id))

      addGlobalOrder({
        id: orderId,
        date: orderDate,
        total,
        status: 'Concluído',
        items: mappedItems,
        customerEmail: email || 'não informado',
        customerName: name || 'não informado',
        couponApplied: appliedDiscount ? appliedDiscount.code : null,
      })

      markUserAsRecurring(email, name)
      clearCart()

      toast({ title: 'Pagamento Aprovado!', description: 'Arquivos enviados para o seu e-mail.' })
    }, 1500)
  }

  const handleCopyPix = () => {
    navigator.clipboard.writeText(pixKey)
    toast({
      title: 'Chave copiada!',
      description: 'Chave PIX copiada para a área de transferência.',
    })
  }

  if (isSuccess) {
    return (
      <div className="container mx-auto px-4 py-20 text-center max-w-lg animate-in fade-in zoom-in">
        <CheckCircle2 className="w-20 h-20 text-green-500 mx-auto mb-6" />
        <h1 className="text-3xl font-bold mb-4">Pagamento Aprovado!</h1>
        <div className="bg-primary/5 p-6 rounded-xl border border-primary/20 mb-8 text-left">
          <p className="text-foreground mb-3 text-center">
            Um e-mail de confirmação foi enviado para{' '}
            <strong className="font-medium">{email || 'seu e-mail'}</strong> com os links para
            download dos seus arquivos.
          </p>
          <p className="text-sm text-muted-foreground text-center">
            Eles também estão disponíveis na sua{' '}
            <Link to="/profile" className="text-primary hover:underline font-medium">
              Biblioteca
            </Link>
            . Lembre-se, há um <strong>limite de 3 downloads por arquivo</strong>.
          </p>
        </div>
        <div className="flex gap-4 justify-center">
          <Button size="lg" onClick={() => navigate('/profile')}>
            Ver Arquivos
          </Button>
          <Button size="lg" variant="outline" onClick={() => navigate('/')}>
            Explorar Mais
          </Button>
        </div>
      </div>
    )
  }

  return (
    <div className="container mx-auto px-4 py-8 max-w-6xl">
      <nav className="flex items-center text-sm text-muted-foreground mb-8">
        <Link to="/" className="hover:text-primary">
          Home
        </Link>
        <ChevronRight className="w-4 h-4 mx-1" />
        <span className="text-foreground font-medium">Finalizar Compra</span>
      </nav>

      <h1 className="text-3xl font-bold mb-8">Finalizar Compra</h1>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 lg:gap-12">
        <div className="lg:col-span-7 space-y-6">
          <form id="checkout-form" onSubmit={handleSubmit} className="space-y-6">
            <div className="bg-card p-6 rounded-2xl border space-y-4 shadow-sm">
              <h2 className="text-xl font-semibold border-b pb-4">Dados Pessoais</h2>
              <div className="space-y-2">
                <Label>Nome Completo</Label>
                <Input
                  required
                  placeholder="Ex: João da Silva"
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                />
              </div>
              <div className="space-y-2">
                <Label>E-mail (para recebimento dos arquivos)</Label>
                <Input
                  required
                  type="email"
                  placeholder="joao@exemplo.com"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                />
              </div>
            </div>

            <div className="bg-card p-6 rounded-2xl border space-y-6 shadow-sm">
              <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 border-b pb-4">
                <h2 className="text-xl font-semibold flex items-center gap-2">
                  <ShieldCheck className="w-5 h-5 text-green-600" /> Pagamento Seguro
                </h2>
                <div className="flex flex-wrap gap-2">
                  <Badge
                    variant="secondary"
                    className="bg-green-100 text-green-800 hover:bg-green-100 border-none shadow-none"
                  >
                    <Lock className="w-3 h-3 mr-1" /> Criptografia SSL
                  </Badge>
                  <Badge
                    variant="secondary"
                    className="bg-blue-100 text-blue-800 hover:bg-blue-100 border-none shadow-none"
                  >
                    <Zap className="w-3 h-3 mr-1" /> Entrega Digital
                  </Badge>
                </div>
              </div>

              <RadioGroup
                value={paymentMethod}
                onValueChange={(v) => setPaymentMethod(v as 'credit_card' | 'pix')}
                className="grid sm:grid-cols-2 gap-4"
              >
                <Label
                  htmlFor="cc"
                  className={`border rounded-xl p-4 flex items-center gap-3 cursor-pointer transition-colors ${paymentMethod === 'credit_card' ? 'border-primary bg-primary/5 ring-1 ring-primary' : 'hover:bg-muted/50'}`}
                >
                  <RadioGroupItem value="credit_card" id="cc" />
                  <CreditCard className="w-5 h-5 text-muted-foreground" /> Cartão de Crédito
                </Label>
                <Label
                  htmlFor="pix"
                  className={`border rounded-xl p-4 flex items-center gap-3 cursor-pointer transition-colors ${paymentMethod === 'pix' ? 'border-primary bg-primary/5 ring-1 ring-primary' : 'hover:bg-muted/50'}`}
                >
                  <RadioGroupItem value="pix" id="pix" />
                  <QrCode className="w-5 h-5 text-muted-foreground" /> PIX
                </Label>
              </RadioGroup>

              {paymentMethod === 'credit_card' ? (
                <div className="space-y-4 animate-in fade-in">
                  <div className="space-y-2">
                    <Label>Número do Cartão</Label>
                    <Input required placeholder="0000 0000 0000 0000" />
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <Label>Validade</Label>
                      <Input required placeholder="MM/AA" />
                    </div>
                    <div className="space-y-2">
                      <Label>CVV</Label>
                      <Input required placeholder="123" />
                    </div>
                  </div>
                </div>
              ) : (
                <div className="bg-secondary/30 p-6 rounded-xl border border-dashed border-primary/30 text-center animate-in fade-in">
                  <div className="bg-white p-4 inline-block rounded-xl border shadow-sm mx-auto mb-4">
                    <QrCode className="w-32 h-32 text-slate-800" />
                  </div>
                  <h4 className="font-semibold mb-1">Escaneie o QR Code ou copie a chave</h4>
                  <p className="text-sm text-muted-foreground mb-4">
                    O pagamento será aprovado instantaneamente.
                  </p>
                  <div className="flex items-center gap-2 max-w-sm mx-auto">
                    <Input value={pixKey} readOnly className="font-mono text-xs bg-background" />
                    <Button
                      type="button"
                      variant="secondary"
                      onClick={handleCopyPix}
                      className="shrink-0"
                    >
                      <Copy className="w-4 h-4 mr-2" />
                      Copiar
                    </Button>
                  </div>
                </div>
              )}
            </div>
          </form>
        </div>

        <div className="lg:col-span-5">
          <div className="bg-secondary/30 p-6 rounded-2xl border sticky top-24 shadow-sm">
            <h2 className="text-xl font-semibold mb-6">Resumo do Pedido</h2>
            <div className="space-y-4 mb-6 max-h-[30vh] overflow-y-auto pr-2">
              {checkoutItems.map((item) => (
                <div key={item.id} className="flex gap-4">
                  <img
                    src={item.images[0]}
                    alt={item.title}
                    className="w-16 h-16 rounded-lg object-cover border bg-background"
                  />
                  <div>
                    <h4 className="font-medium text-sm leading-tight">{item.title}</h4>
                    <p className="text-xs text-muted-foreground">Qtd: {item.quantity}</p>
                    <div className="font-bold text-primary">
                      R$ {(item.price * item.quantity).toFixed(2).replace('.', ',')}
                    </div>
                  </div>
                </div>
              ))}
            </div>

            <Separator className="my-6" />

            <div className="space-y-3 mb-6">
              <Label className="text-sm flex items-center gap-2 mb-2">
                <Tag className="w-4 h-4" /> Cupom de Desconto
              </Label>
              <div className="flex gap-2">
                <Input
                  placeholder="Ex: DESC10"
                  value={couponCode}
                  onChange={(e) => setCouponCode(e.target.value.toUpperCase())}
                  disabled={!!appliedDiscount}
                  className="bg-background"
                />
                <Button
                  type="button"
                  variant={appliedDiscount ? 'outline' : 'secondary'}
                  onClick={handleApplyCoupon}
                >
                  {appliedDiscount ? 'Remover' : 'Aplicar'}
                </Button>
              </div>
            </div>

            <Separator className="my-6" />

            <div className="space-y-3 mb-6">
              <div className="flex justify-between text-muted-foreground">
                <span>Subtotal</span>
                <span>R$ {subtotal.toFixed(2).replace('.', ',')}</span>
              </div>
              {appliedDiscount && (
                <div className="flex justify-between text-green-600 font-medium bg-green-50 dark:bg-green-950/20 px-3 py-2 rounded-lg -mx-3">
                  <span>
                    {coupons.find((c) => c.id === appliedDiscount.id)?.isWelcomeCoupon
                      ? `Boas-Vindas (${appliedDiscount.code})`
                      : `Desconto (${appliedDiscount.code})`}
                  </span>
                  <span>- R$ {discountAmount.toFixed(2).replace('.', ',')}</span>
                </div>
              )}
              <div className="flex justify-between text-green-600">
                <span>Frete (Digital)</span>
                <span>Grátis</span>
              </div>
              <div className="flex justify-between text-xl font-bold pt-4 border-t">
                <span>Total</span>
                <span className="text-primary">R$ {total.toFixed(2).replace('.', ',')}</span>
              </div>
            </div>

            <div className="bg-amber-50 dark:bg-amber-950/30 border border-amber-200 dark:border-amber-900/50 rounded-xl p-4 mb-6 flex gap-3 text-sm text-amber-800 dark:text-amber-200 shadow-sm animate-in fade-in">
              <AlertCircle className="w-5 h-5 shrink-0 mt-0.5 text-amber-600 dark:text-amber-400" />
              <div>
                <strong className="block font-semibold mb-1">Política de Reembolso</strong>
                Por se tratar de um arquivo digital (não sendo enviado nenhum produto físico), não
                aceitamos devoluções ou reembolsos após a compra.
              </div>
            </div>

            <Button
              type="submit"
              form="checkout-form"
              size="lg"
              className="w-full h-14 text-lg transition-transform hover:scale-[1.02]"
              disabled={isLoading}
            >
              {isLoading
                ? 'Processando...'
                : paymentMethod === 'pix'
                  ? 'Simular Pagamento PIX'
                  : 'Confirmar Compra'}
            </Button>
            <p className="text-center flex items-center justify-center gap-2 text-sm text-muted-foreground mt-6">
              <Lock className="w-4 h-4" /> Pagamento 100% Seguro
            </p>
          </div>
        </div>
      </div>
    </div>
  )
}
